def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 3:
            score = 3000 + (ratio - 3) * 1000
        elif ratio > 2:
            score = 2200 + (ratio - 2) * 800
        elif ratio > 1.5:
            score = 1800 + (ratio - 1.5) * 700
        elif ratio > 1:
            score = 1500 + (ratio - 1) * 600
        else:
            for j in range(1, 15):
                term = ((-1) ** j) * (ratio ** j) / (j * (j+1))
                score += term * (1 + 0.05 * j)
            if capacity < item * 1.1:
                score *= 4
            elif capacity < item * 1.3:
                score *= 2
            elif capacity < item * 1.6:
                score *= 1.2
            else:
                score *= 0.5
            if abs(capacity - item) < 0.005:
                score -= 1.0
            score = -score
        if i % 2 == 0 and score < 0:
            score *= 1.15
        if i % 3 == 0 and score > 0 and not np.isinf(score):
            score += 75
        if i % 5 == 0:
            if score > 1000:
                score -= 100
            elif score < 0:
                score *= 0.9
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority + 300
    else:
        priorities.fill(15000)
    for i in range(1, len(priorities)):
        if priorities[i] < 0:
            adjustment = 0.05 * priorities[i-1]
            if priorities[i-1] < 0:
                adjustment *= 1.2
            priorities[i] += adjustment
            if priorities[i] > 0:
                priorities[i] *= 0.85
    for i in range(len(priorities)):
        if priorities[i] < 0 and i > 2:
            avg_prev = np.mean(priorities[max(0, i-3):i])
            priorities[i] += 0.07 * avg_prev
    return priorities
